DROP TABLE IF EXISTS `villagers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `villagers` (
  `villager_id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID of the villager',
  `species_id` int unsigned NOT NULL COMMENT 'ID of the villager''s species',
  `personality_id` int unsigned NOT NULL COMMENT 'ID of the villager''s personality type',
  `name` varchar(100) NOT NULL COMMENT 'villager''s name',
  `gender` enum('Male','Female') NOT NULL COMMENT 'gender identity',
  `birthday` date NOT NULL,
  `subtype` enum('A','B') NOT NULL,
  PRIMARY KEY (`villager_id`),
  KEY `villagers_species_species_id_fk` (`species_id`),
  KEY `villagers_personalities_personality_id_fk` (`personality_id`),
  CONSTRAINT `villagers_personalities_personality_id_fk` FOREIGN KEY (`personality_id`) REFERENCES `personalities` (`personality_id`),
  CONSTRAINT `villagers_species_species_id_fk` FOREIGN KEY (`species_id`) REFERENCES `species` (`species_id`),
  CONSTRAINT `villagers_traits_villager_id_fk` FOREIGN KEY (`villager_id`) REFERENCES `traits` (`villager_id`)
) ENGINE=InnoDB AUTO_INCREMENT=414 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

